import React, { Component } from 'react';
import API from '../utils/API';
import Container from "./container.component";
import { Redirect } from "react-router-dom";

export default class Questions extends Component {
    state = {
        selectedOption: "",
        questions: [],
        question: {},
        questionNum: 0,
        answers: [],
        answerID: [],
        user: ""
    }

    componentDidMount() {
        API.getQuestions()
            .then(res => {
                this.setState({
                    questions: res.data
                })
                this.setState({
                    selectedOption: "",
                    question: this.state.questions[this.state.questionNum]
                })
            });

        // API.LOC_API()
        //     .then(res => {
        //         // console.log(res.data.trending_content);
        //         console.log(res.data.results);
        //     })
    }

    saveAnswers(id, answers) {
        API.saveResults({
            userID: id,
            answers: answers
        })
    }

    onValueChange = event => {
        this.setState({
            selectedOption: event.target.value
        });
    }

    setQuestion() {
        this.setState({
            questionNum: this.state.questionNum + 1,
            question: this.state.questions[this.state.questionNum]
        })
    }

    handleFormSubmit = event => {
        event.preventDefault();
        if ((this.state.questionNum < this.state.questions.length) && this.state.selectedOption) {
            this.setState({
                selectedOption: "",
                // questionNum: this.state.questionNum + 1,
                answers: this.state.answers.concat(this.state.selectedOption),
                answerID: this.state.questionNum
            });
            this.forceUpdate(this.setQuestion);
        }
        if (this.state.questionNum === 11) {
            this.setState({
                redirect: "/mystats"
            });
            // API call goes here ********************
            this.saveAnswers(this.props.location.state.id, this.state.answers);
        }
    }

    render() {
        if (this.state.redirect) {
            return <Redirect to={{
                pathname: this.state.redirect,
                state: {
                    id: this.props.location.state.id,
                    answers: this.state.answers
                }
            }} />
        }
        return (
            <Container>
                <div className="container radio w-75">
                    <h3><p>question number : {this.state.questionNum + 1}</p></h3>
                    <hr />
                    <form onSubmit={this.handleFormSubmit}>
                        <div>
                            <div className="card p-2 m-4">
                                <p>{this.state.question.question}</p>
                                <hr />
                                <p>
                                    <label>
                                        <input
                                            type="radio"
                                            value="a"
                                            checked={this.state.selectedOption === "a"}
                                            onChange={this.onValueChange}
                                        />
                                        &nbsp;&nbsp;{this.state.question.a}<br />
                                    </label>
                                </p>
                                <p>
                                    <label>
                                        <input
                                            type="radio"
                                            value="b"
                                            checked={this.state.selectedOption === "b"}
                                            onChange={this.onValueChange}
                                        />
                                        &nbsp;&nbsp;{this.state.question.b}<br />
                                    </label>
                                </p>
                                <p>
                                    <label>
                                        <input
                                            type="radio"
                                            value="c"
                                            checked={this.state.selectedOption === "c"}
                                            onChange={this.onValueChange}
                                        />
                                        &nbsp;&nbsp;{this.state.question.c}<br />
                                    </label>
                                </p>
                                <p>
                                    <button
                                        className="save btn btn-info"
                                        type="submit">answer
                                        </button>
                                </p>
                            </div>
                        </div>
                    </form>
                </div>
            </Container>
        )
    }
}