import React, { Component } from 'react';
import { Link } from 'react-router-dom';
import API from '../utils/API';
// import '../utils/App.css';

export default class Navbar extends Component {

  state = {
    logout: false
  }

  logout(event) {
    event.preventDefault()
    console.log('logging out')
    API.logoutUser('/user/logout').then(response => {
      console.log(response.data)
      if (response.status === 200) {
        this.props.updateUser({
          loggedIn: false,
          username: null
        })
      }
    }).catch(error => {
      console.log('Logout error')
    })
  }

  render() {
    const loggedIn = this.props.loggedIn;
    console.log('navbar render, props: ');
    console.log(this.props);
    return (
      <div>
        <header className="navbar App-header" id="nav-container">
          <div className="col-4">
            {loggedIn ? (
              <section className="navbar-section" >
                <Link to="#" className="btn btn-link text-secondary" onClick={this.logout}>
                  <span className="text-secondary">logout</span></Link>
              </section>
            ) : (
                <section className="navbar-section">
                  {/* <nav className="nav nav-justified"> */}
                    <a className="btn btn-link text-secondary" href="/questions" onClick={() => { }}>questions</a >
                    <a className="btn btn-link text-secondary" href="/edit-questions" onClick={() => { }}>edit questions</a>
                    <a className="btn btn-link text-secondary" href="/new-questions" onClick={() => { }}>insert questions</a>
                    <a className="btn btn-link text-secondary" href="/users" onClick={() => { }}>users</a>
                    <a className="btn btn-link text-secondary" href="/person" onClick={() => { }}>person</a>
                    <a className="btn btn-link text-secondaryy" href="/signup" onClick={() => { }}>sign up</a>
                  {/* </nav > */}
                </section>
              )
            }
          </div>
        </header>
      </div>
    )
  }
}