import React, { Component } from 'react';
import API from '../utils/API';
import Container from "./container.component";
import { Redirect } from "react-router-dom";

export default class Users extends Component {
    state = {
        selectedOption: "",
        users: [],
        tank: "",
        questions: [],
        count: 0
        // redirect: "/"
    }

    componentDidMount() {
        API.getQuestions()
            .then(res => {
                // console.log(".....q.....");
                // console.log(res);
                this.setState({
                    questions: res.data
                })
                // console.log(".....q.....");
                // console.log("... mount");
                // console.log(this.state.questions);
            })
        API.getResults()
            .then(res => {
                console.log(res.data);
            })
    }



    componentDidUpdate() {
    }

    onValueChange = event => {
        this.setState({
            selectedOption: event.target.value
        });
    }

    handleFormSubmit = event => {
        // event.preventDefault();
        // console.log("selectedOption: " + this.state.selectedOption);
        if (this.state.selectedOption) {
            this.setState({
                tank: this.state.selectedOption,
                selectedOption: "",
                redirect: "/questions"
            });
            // console.log(".....users.handleFormSubmit........")
            // console.log("selected: " + this.state.selectedOption);
            // console.log("user: " + this.state.tank);
        }
    }
    // counter = event => {
    //     this.setState({
    //         count: this.state.count + 1
    //     })
    //     return this.state.count;
    // }

    render() {
        var min = 1;
        var max = 1000;
        // var rand =  min + (Math.random() * (max-min));
        // console.log(rand);
        // console.log(this.props);
        // console.log(this.props.location.state.answers);
        // console.log(this.props.location.state.id);
        // console.log("... users");
        if (this.state.redirect) {
            return <Redirect to={{
                pathname: this.state.redirect,
                state: {
                    id: this.state.tank
                }
            }} />
        }
        return (
            <Container>
                <div className="container radio w-50">
                    <h3><p>your stats</p></h3>
                    <hr />
                    <div className="row">
                        <div className="col">
                            {this.state.questions.map(question => (
                                <div className="card p-2 m-4" key={question._id}>
                                    <p>correct: {question.answer}</p>
                                </div>
                            ))}
                        </div>
                        <div className="col">
                            {this.props.location.state.answers.map(answer => (
                                <div className="card p-2 m-4" key={min + (Math.random() * (max - min))}>
                                    <p>yours: {answer}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </Container>
        )
    }
}